var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오오, 바다 건너편에서 먹는 케밥은 역시 맛이 색다르네요.","JPN":"おお、海を越えて食べるケバブの味は格別ですね。","ENG":"Ooh, kebabs sure taste different overseas.","TWN":"哇喔～在大海對面吃沙威瑪特別美味呢～"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님은 안 드세요? 하루 종일 탐문 다니느라 배고프셨잖아요?","JPN":"警視様は食べないんですか？　一日中聞き込み捜査していてお腹空いたでしょ？","ENG":"Aren't you going to eat, Major? You must be starving after spending all day investigating.","TWN":"警政大人不吃嗎？你打聽一整天不餓嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우린 지금 공무 수행 중이야. 강소영 경위.","JPN":"私たちは今公務遂行中よ、マエカワ警部補。","ENG":"We're on duty right now, Lieutenant Kang.","TWN":"姜素英警衛，我們正在執勤中。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여행 온 관광객처럼 길거리 음식이나 사먹으면서 한가하게 쉴 때가 아니라고.","JPN":"旅行中の観光客みたいに食べ歩きしながらのんびりしている場合じゃないの。","ENG":"Now's not the time to be relaxing and indulging in street food like a tourist.","TWN":"我們不是來玩的觀光客，現在不是買路邊小吃，悠閒休息的時候。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러면요?","JPN":"じゃあどうすれば？","ENG":"It isn't?","TWN":"不然咧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그걸 몰라서 물어?! 이번 대규모 탈옥 사태는 경찰의 명예가 걸린 사태야!","JPN":"そんなこと聞くの！？　今回の大規模脱獄事件は警察の名誉がかかった事件よ！","ENG":"Of course not! The honor of the police is at stake with this mass jailbreak!","TWN":"你是認真的嗎？！這次的大規模越獄事件，害我們警察名譽掃地！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우리가 이러고 있는 동안에도 탈옥한 범죄자들이 무슨 짓을 저지를지 모르잖아!","JPN":"私たちがこうしている間に脱獄囚たちが何をしでかすか心配じゃないの？","ENG":"There's no telling what those escaped convicts are doing as we speak!","TWN":"我們在這邊悠悠哉哉的時候，那些越獄犯說不定正在幹什麼壞事呢！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 왜 이러실까. 다 먹고 살자고 하는 일인데.","JPN":"え～結局仕事っていいもん食って生きていくためにするもんですよ。","ENG":"Aw, come on. A woman's gotta eat though.","TWN":"哎唷～幹嘛這樣～大家都是混口飯吃嘛～"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애초에 현지에서 수사에 협조해 주지 않으면 저희 단독으로 움직이는 건 월권이라고요?","JPN":"そもそも現地で捜査に協力してくれなければ、私たちが単独で動くのも越権行為ですよ？","ENG":"Besides, acting on our own without the local police backing us up is a violation of jurisdiction.","TWN":"我們一開始又沒有在當地協助調查，這樣單獨行動是越權好嗎？　"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그리고 이건 엘카노 주교 한 명 잡는다고 끝날 일이 아니에요. 사태를 일으킨 주범이 핵심이죠.","JPN":"それに、これはエルカノ司教を捕まえたところで済む事件でもありませんよ。事件を起こした主犯は別にいますから。","ENG":"Plus, catching Elcano won't solve this either. There's another key player behind the whole case.","TWN":"而且，這件事又不是抓到一個埃爾卡諾主教就真相大白，引發事件的主嫌才是重點。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님이 이런 데서 열내다 쓰러지기라도 하면 청장님한테 멱살 잡힐 사람은 저라고요.","JPN":"警視様がこんなところで頑張りすぎて熱でも出したら、署長に大目玉を食らうのは私ですし。","ENG":"And I wouldn't want you to overwork yourself, only to pass out overseas. The commissioner would have my head.","TWN":"萬一你在這個地方累到昏倒，那局長一定會唯我是問。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥. 과로로 쓰러지는 건 무능력자들한테나 해당되는 얘기고.","JPN":"ふん、過労で倒れるのは無能力者に限った話よ。","ENG":"Hmph. Only the incompetent pass out from exhaustion.","TWN":"哼，沒用的人才會因為過勞而昏倒。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러지 말고 자, 아~ 하세요. 제가 먹여 드리면 되죠?","JPN":"まあまあ、わかったらからあ～んしてください。実は食べたいんでしょ？","ENG":"Come on, don't be like that and open wide. I'll feed you so you won't get your fingers greasy.","TWN":"不要那樣，來，啊～嘴巴張開，我餵你總行了吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위!!","JPN":"マエカワ警部補！！","ENG":"Lieutenant Kang!!","TWN":"姜素英警衛！！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……방금 그 소리, 들었어?","JPN":"……今の音、聞こえた？","ENG":"Did you just hear that?","TWN":"你有聽到那個聲音嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 폭발음이네요.","JPN":"はい、爆発音ですね。","ENG":"Yes. Sounded like an explosion.","TWN":"嗯，是爆炸聲。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"관광지도에 따르면 공업지대 방향이에요. 느낌이 좋지 않은데요.","JPN":"観光地図によると工業地帯方向です。悪い予感がします。","ENG":"According to the tourist map, it came from around the Industrial Area. I've got a bad feeling about this...","TWN":"看旅遊地圖似乎是工業區的方向，我有不好的預感。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"대체 왜 관광지도인지는 묻지 않을게. 당장 버려, 그거.","JPN":"なぜ観光地図の情報なのかは聞かないことにするわ。それ、すぐに捨てなさい。","ENG":"I'm not even going to ask why you're using a tourist map. Get rid of that thing. Now.","TWN":"我不會問你為什麼會有旅遊地圖，立刻給我扔掉。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"강소영 경위? 자네가 이 동네에 어쩐 일인가?","JPN":"マエカワ警部補？　君がこの町に何の用かね？","ENG":"Lieutenant Kang? What are you doing in this neighborhood?","TWN":"姜素英警衛？什麼風把你吹來的？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어? 아저씨야말로 완전 무장 상태로 어디 가세요? 침식재난인가요?","JPN":"あれ？　おじさんこそ完全武装状態でどこに行くんですか？　侵食災害ですか？","ENG":"Huh? I could ask you the same! Where are you going all geared up like that? Do we have a Corruption Disaster on our hands?","TWN":"嗯？大叔你全副武裝是要去哪？發生侵蝕災難嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"아니. 관리국의 수배령이 내려진 자가 이 도시에 나타났어. 경찰 측에는 소식이 조금 늦게 전해졌나 보군.","JPN":"いや。管理局から指名手配中の者がこの都市に現れてな。警察には情報の共有が少し遅れたみたいだな。","ENG":"No. Someone on the Administration's Red Notice turned up in this city. I guess it took a little longer for the news to reach the police.","TWN":"沒有，是管理局發出通緝令的人出現在這裡，看來警方的消息不太靈通呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저 분 말이 맞아. 방금 내 단말에도 협조 요청이 들어왔어.","JPN":"あの方の言うとおりよ。ちょうど今私の端末にも協力要請が来た。","ENG":"He's right. I just got the memo on my device requesting support.","TWN":"他說的沒錯，剛才我也有收到協助的請求。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"앞서 투입됐던 도시 경비대만으로는 벅찬 모양이야. 태스크포스들도 동원된 상태다.","JPN":"先に投入された都市警備隊だけでは手に余るらしい。近くのタスクフォースカンパニーも動員された状態だ。","ENG":"It sounds like the City Guard they've already committed isn't enough. They've also mobilized TASKFORCEs.","TWN":"光靠之前投入的城市守衛隊似乎有點吃力，因此還動員了特遣勢力。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이야, 태스크포스라 고생이 많으시겠네요.","JPN":"いやあ～タスクフォースカンパニーもですか。大変ですね～。","ENG":"Aww, that must mean things are going to get hectic for you now.","TWN":"哎呀，特遣勢力真的很辛苦呢～"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 저희도 엘릭서를 만들려는 흉악한 범죄자를 찾아야 해서 이만……","JPN":"ですが、私たちもエリクサーを作ろうとする凶悪犯罪者を探さないといけないので、この辺で失礼……","ENG":"I wish we could help, but we've got our own Elixir-brewing felon to catch…","TWN":"不過我們還要去找製造聖水的犯人，就先告辭囉……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저희도 돕겠습니다.","JPN":"私たちも協力します。","ENG":"We'll help.","TWN":"我們也會幫忙的。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님? 갑자기 무슨 말씀이세요?","JPN":"警視様！？　いきなりどうしたんですか？","ENG":"Major? What are you talking about?","TWN":"警政大人？你在胡說什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"눈앞에서 사건이 터졌는데 모른 척 할 수는 없어.","JPN":"目の前で事件が起きたのに見て見ぬふりはできないじゃない。","ENG":"We can't simply turn a blind eye to a live situation unfolding right in front of us.","TWN":"事情就發生在我眼前，總不能裝作不知道吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"태스크포스에 협조하는 건 월권 행위도 아니잖아?","JPN":"タスクフォースカンパニーに協力するのは越権行為でもないでしょ？","ENG":"Besides, cooperating with a TASKFORCE isn't a violation of jurisdiction, is it?","TWN":"而且協助特遣勢力不算越權吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"리플레이서 사태 때 어땠는지 벌써 잊으셨어요?","JPN":"リプレイサー事件の時はどうだったのか、もう忘れたんですか？","ENG":"Did you already forget what happened during the Replacer incident?","TWN":"你忘記克隆集團事件嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"공무원인 저희가 이런 일에 잘못 엮이면 감당이 안 된다니까요.","JPN":"公務員である私たちがこんな事件に巻き込まれたら手に負えなくなりますよ？","ENG":"Civil servants like us can't handle the backlash if we get involved in stuff like this.","TWN":"身為公務員，牽扯到這種事的話，後果我們承擔不起啦。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러면 경찰로서 시민들이 공포에 질리는 모습을 그냥 두고보란 거야?","JPN":"それじゃあ警察として市民たちが恐怖に怯えているのを黙って見てろってこと？","ENG":"Then you expect us to just sit and watch the civilians tremble in terror? It's our calling as police officers to protect and serve!","TWN":"難道身為警察，你要我無視深陷恐懼的市民嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"나는 이 분들과 함께 움직이겠어. 경위는 내가 없는 동안 엘카노의 행방을 탐문해 두도록 해. ","JPN":"私はこの方たちと一緒に行動するわ。警部補は私がいない間にエルカノの行方について聞き込み捜査を進めておいて。","ENG":"I'm going to go assist this gentleman and his team. In the meantime, you're welcome to investigate Elcano's whereabouts. ","TWN":"我要和他們一起行動，我不在的這段時間，警衛你就繼續調查埃爾卡諾的下落吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하아…… 나중에 또 잘못했다면서 훌쩍거리실 거면서.","JPN":"はあ……後でまた私が悪かったってしくしく泣かれたら困りますよ。","ENG":"Ugh… I just know you're going to bawl your eyes out later in regret. AGAIN.","TWN":"哀……之後又要在那邊哭哭啼啼說，是我不對…"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"누, 누가 훌쩍거렸다는 거야?! 그거 상관 모욕죄야, 강소영 경위!","JPN":"だ、誰が泣いたっていうの！？　それは上官への侮辱罪よ、マエカワ警部補！","ENG":"I-I never bawled my eyes out! I'll have you know disrespecting your superior officer is a punishable offense, Lieutenant!","TWN":"誰…誰哭哭啼啼啦？！姜素英警衛，你這是侮辱上司罪！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 네. 저 같은 일개 경위이야 시키는 대로 해야죠.","JPN":"はいはい。私のような一介の警部補は言われたとおりにするしかありませんね。","ENG":"Yeah, yeah. A lowly lieutenant like me should just do as she's told.","TWN":"好好好，像我這種小小警衛，警政大人怎麼說我就怎麼做。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"운전은 저한테 맡겨요, 아저씨. 수배자보다 한 발 앞서고 싶으시죠?","JPN":"運転は私に任せてください、おじさん。指名手配者より一歩先に動きたいでしょ？","ENG":"You can leave the driving to me, mister. If you want to stay a step ahead of the suspect, that is.","TWN":"大叔，我來開車，你想要超前通緝犯一步吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"……신호는 꼭 지켜야 한다.","JPN":"……信号は必ず守ってくれ。","ENG":"…Try not to run any red lights.","TWN":"……一定要遵守交通規則。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};